from flask import Flask, request
import psycopg2
from elasticsearch_apm import ElasticApm

app = Flask(__name__)
apm = ElasticApm(service_name='your-application-name')
apm.init_tracing()

@app.route('/')
def hello():
    conn = psycopg2.connect(user="username", password="password", host="localhost", port="5432", database="database")
    cursor = conn.cursor()

    # SQL query for demonstration purposes
    cursor.execute("SELECT * FROM users LIMIT 10")
    rows_fetch = cursor.fetchall()

    apm.current_transaction.set_span('Database Query', child_of=apm.current_transaction)
    for row in rows_fetch:
        print(f"{row[0]} ({row[1]})")

    cursor.close()
    conn.close()

    apm.current_span.set_tag("response", "Hello World!")
    return "Hello World!"

if __name__ == "__main__":
    app.run(debug=True)